// 根据聊天标题返回默认预设消息；若非示例项则返回主界面两条问候语
+ (NSArray<AIChatListMessageModel *> *)defaultPresetMessagesForChatId:(NSString *)chatId {
    // 先从聊天列表查找该项，依据标题判断预设内容
    NSArray<AIChatListItemModel *> *list = [self loadChatList];
    AIChatListItemModel *target = nil;
