                                @"Why do I always attract scumbags/scumbags?" ];
            for (NSString *t in texts) {
                [msgs addObject:[[AIChatListMessageModel alloc] initWithText:t time:[NSDate date] type:AIChatListMessageTypeReceived context:@"" Done:NO]];
            }
        } else if ([title isEqualToString:@"Outdoor sports"]) {
            NSArray *texts = @[ @"Hello, what is your favorite sport? Football; Basketball; run; Swimming; Riding?",
                                @"I usually run 5 kilometers in the morning and play ball in the afternoon"];
            for (NSString *t in texts) {
                [msgs addObject:[[AIChatListMessageModel alloc] initWithText:t time:[NSDate date] type:AIChatListMessageTypeReceived context:@"" Done:NO]];
            }
        } else if ([title isEqualToString:@"Music"]) {
            NSArray *texts = @[ @"Open the music player, and over and over again, there are only a few songs that you can't listen to well. I don't know what you want to listen to, but I can tell you what genre you like and recommend some popular songs that you like recently.",
                                 @"I'm so tired after work, I want to listen to some relaxing and healing pure music.",
                                 @"Need to focus on studying/working, pure music recommendation",
                                 @"Recommend a fairy song that won't get tired of a single loop" ];
            for (NSString *t in texts) {
                [msgs addObject:[[AIChatListMessageModel alloc] initWithText:t time:[NSDate date] type:AIChatListMessageTypeReceived context:@"" Done:NO]];
            }
        } else if ([title isEqualToString:@"Learn"]) {
            NSArray *texts = @[ @"What do you want to learn? I can help you develop a reasonable study plan to double your learning efficiency",
                                @"Do you like reading books?"];
            for (NSString *t in texts) {
                [msgs addObject:[[AIChatListMessageModel alloc] initWithText:t time:[NSDate date] type:AIChatListMessageTypeReceived context:@"" Done:NO]];
            }
        }
    }
    // 非示例项或未命中标题时，退化为两条问候语；优先使用该聊天项的标题作为名称
    if (msgs.count == 0) {
        NSString *assistant = nil;
        if (target && target.title.length > 0) {
            assistant = target.title;
        } else {
            assistant = [AIChatListMessageModel assistantDisplayName];
        }
        NSString *g1Text = [NSString stringWithFormat:@"Are you going to watch a movie after work tonight?"];
//        NSString *g2Text = [NSString stringWithFormat:@"你好, %@!", assistant];
        AIChatListMessageModel *g1 = [[AIChatListMessageModel alloc] initWithText:g1Text time:[NSDate date] type:AIChatListMessageTypeReceived context:@"" Done:NO];
//        AIChatListMessageModel *g2 = [[AIChatListMessageModel alloc] initWithText:g2Text time:[NSDate date] type:AIChatListMessageTypeSent context:@"" Done:NO];
        [msgs addObject:g1];
//        [msgs addObject:g2];
    }
    return msgs;
}

