- (UITableView *)tableView {
    if (!_tableView) {
        _tableView = [[UITableView alloc] initWithFrame:CGRectZero style:UITableViewStylePlain];
        _tableView.backgroundColor = [UIColor clearColor];
        _tableView.tableFooterView = [UIView new];
        _tableView.showsVerticalScrollIndicator = NO;

        // 头像头图：使用当前会话的头像，尺寸 84 * 84，圆角，水平居中
        CGFloat headerHeight = ZOOM(86);
        UIView *headerContainer = [[UIView alloc] initWithFrame:CGRectMake(0, 0, self.view.bounds.size.width, headerHeight)];
        headerContainer.backgroundColor = [UIColor clearColor];

        UIImage *avatarImage = nil;
        // 优先从聊天列表项读取头像：若有自定义头像文件使用文件；否则使用资源 icon；再否则默认头像
        NSArray<AIChatListItemModel *> *list = [AIChatListStorage loadChatList];
        AIChatListItemModel *targetItem = nil;
        for (AIChatListItemModel *it in list) {
            if ([it.chatId isEqualToString:self.chatId]) { targetItem = it; break; }
        }
        if (targetItem) {
            if (targetItem.avatarPath.length > 0) {
                NSString *abs = [[AIChatListStorage documentsPath] stringByAppendingPathComponent:targetItem.avatarPath];
                UIImage *img = [UIImage imageWithContentsOfFile:abs];
                avatarImage = img;
            } else if (targetItem.icon.length > 0) {
                avatarImage = [UIImage imageNamed:targetItem.icon];
            }
        }
        if (!avatarImage) {
            // 仍无头像时，尝试使用按 chatId 的绝对路径；最后回退默认
            NSString *absPath = [AIChatListStorage avatarPathForChatId:self.chatId];
            if ([[NSFileManager defaultManager] fileExistsAtPath:absPath]) {
                avatarImage = [UIImage imageWithContentsOfFile:absPath];
            }
        }
        if (!avatarImage) {
            avatarImage = [UIImage imageNamed:@"A_defaultAvatar"];
        }

        CGFloat avatarSize = ZOOM(54);
        CGFloat topInset = ZOOM(16);
//        CGFloat avatarBackViewSize = ZOOM(92);
//        CGFloat backViewTopInset = ZOOM(20);
//        UIView *avatarBackView = [[UIView alloc] initWithFrame:CGRectMake((headerContainer.bounds.size.width - avatarBackViewSize)/2.0,
//                                      backViewTopInset,
//                                      avatarBackViewSize,
//                                      avatarBackViewSize)];
//        avatarBackView.backgroundColor = [UIColor whiteColor];
//        avatarBackView.layer.cornerRadius = avatarBackViewSize/2.0;
//        avatarBackView.clipsToBounds = YES;
//        [headerContainer addSubview:avatarBackView];
        UIImageView *avatarView = [[UIImageView alloc] initWithImage:avatarImage];
        avatarView.contentMode = UIViewContentModeScaleAspectFill;
        avatarView.frame = CGRectMake(ZOOM(16),
                                      topInset,
                                      avatarSize,
                                      avatarSize);
        avatarView.layer.cornerRadius = avatarSize/2.0;
        avatarView.clipsToBounds = YES;
        [headerContainer addSubview:avatarView];
        _tableView.tableHeaderView = headerContainer;
    }
    return _tableView;
}

