}

+ (void)ensurePresetMessagesExistForChat:(AIChatListItemModel *)item texts:(NSArray<NSString *> *)texts {
    NSString *path = [self messagesFilePathForChatId:item.chatId];
    if ([[NSFileManager defaultManager] fileExistsAtPath:path]) {
        return;
    }
    NSMutableArray<AIChatListMessageModel *> *msgs = [NSMutableArray array];
    for (NSString *t in texts) {
        AIChatListMessageModel *m = [[AIChatListMessageModel alloc] initWithText:t time:[NSDate date] type:AIChatListMessageTypeReceived context:@"" Done:NO];
        [msgs addObject:m];
    }
    [self saveMessages:msgs forChatId:item.chatId];
}

+ (NSString *)documentsPath {
    NSArray *paths = NSSearchPathForDirectoriesInDomains(NSDocumentDirectory, NSUserDomainMask, YES);
    NSString *doc = paths.firstObject ?: NSTemporaryDirectory();
    return doc;
}

+ (NSString *)chatListFilePath {
    return [[self documentsPath] stringByAppendingPathComponent:@"ai_chat_list_chats.json"];
}

+ (NSString *)messagesDirPath {
    NSString *dir = [[self documentsPath] stringByAppendingPathComponent:@"ai_chat_list_chats"];
    if (![[NSFileManager defaultManager] fileExistsAtPath:dir]) {
        [[NSFileManager defaultManager] createDirectoryAtPath:dir withIntermediateDirectories:YES attributes:nil error:nil];
    }
    return dir;
}

+ (NSString *)avatarsDirPath {
    NSString *dir = [[self documentsPath] stringByAppendingPathComponent:@"ai_chat_list_avatars"];
    if (![[NSFileManager defaultManager] fileExistsAtPath:dir]) {
        [[NSFileManager defaultManager] createDirectoryAtPath:dir withIntermediateDirectories:YES attributes:nil error:nil];
    }
    return dir;
}

+ (NSString *)messagesFilePathForChatId:(NSString *)chatId {
    return [[self messagesDirPath] stringByAppendingPathComponent:[NSString stringWithFormat:@"%@.json", chatId ?: @""]];
}

+ (NSString *)avatarPathForChatId:(NSString *)chatId {
    return [[self avatarsDirPath] stringByAppendingPathComponent:[NSString stringWithFormat:@"%@.png", chatId ?: @""]];
}

+ (NSMutableArray<AIChatListItemModel *> *)loadChatList {
    NSMutableArray<AIChatListItemModel *> *list = [NSMutableArray arrayWithArray:[self defaultChatItems]];
    [list addObjectsFromArray:[self loadCustomChatList]];
    return list;
}

+ (void)saveChatList:(NSArray<AIChatListItemModel *> *)list {
    [self saveCustomChatList:list];
}

+ (NSMutableArray<AIChatListMessageModel *> *)loadMessagesForChatId:(NSString *)chatId {
    NSMutableArray<AIChatListMessageModel *> *list = [NSMutableArray array];
    NSString *path = [self messagesFilePathForChatId:chatId];
    NSData *data = [NSData dataWithContentsOfFile:path];
    if (data) {
        NSError *err = nil;
        id obj = [NSJSONSerialization JSONObjectWithData:data options:0 error:&err];
        if (!err && [obj isKindOfClass:[NSArray class]]) {
            for (NSDictionary *d in (NSArray *)obj) {
                if (![d isKindOfClass:[NSDictionary class]]) continue;
                // 重用 AIChatListMessageModel 的映射格式
                NSString *text = d[@"text"] ?: @"";
                NSNumber *ts = d[@"time"] ?: @(NSDate.date.timeIntervalSince1970);
                NSDate *time = [NSDate dateWithTimeIntervalSince1970:ts.doubleValue];
                AIChatListMessageType type = (AIChatListMessageType)[d[@"type"] integerValue];
                NSString *context = d[@"context"] ?: @"";
                BOOL done = [d[@"done"] boolValue];
                AIChatListMessageModel *m = [[AIChatListMessageModel alloc] initWithText:text time:time type:type context:context Done:done];
                NSNumber *mn = d[@"messagenum"]; if (mn) { m.messagenum = mn.integerValue; }
                [list addObject:m];
            }
        }
    }
    return list;
}

+ (void)saveMessages:(NSArray<AIChatListMessageModel *> *)messages forChatId:(NSString *)chatId {
    NSMutableArray *arr = [NSMutableArray arrayWithCapacity:messages.count];
    for (AIChatListMessageModel *m in messages) {
        NSDictionary *d = @{ @"text": m.text ?: @"",
                             @"time": @([m.time timeIntervalSince1970]),
                             @"type": @(m.type),
                             @"context": m.context ?: @"",
                             @"done": @(m.done),
                             @"messagenum": @(m.messagenum) };
        [arr addObject:d];
    }
    NSError *err = nil;
    NSData *data = [NSJSONSerialization dataWithJSONObject:arr options:0 error:&err];
    if (!err && data) {
        [data writeToFile:[self messagesFilePathForChatId:chatId] atomically:YES];
    }
}

+ (void)clearMessagesForChatId:(NSString *)chatId {
    NSString *path = [self messagesFilePathForChatId:chatId];
    [[NSFileManager defaultManager] removeItemAtPath:path error:nil];
}

