#import "AIChatListMessageCell.h"
#import "Masonry.h"
#import "PrefixHeader.h"

@interface AIChatListMessageCell()

@property (nonatomic, strong) UIImageView *avatarImageView;
@property (nonatomic, strong) UIView *bubbleView;
@property (nonatomic, strong) UILabel *messageLabel;
@property (nonatomic, assign) BOOL isSenderFlag;

@end

@implementation AIChatListMessageCell

- (instancetype)initWithStyle:(UITableViewCellStyle)style reuseIdentifier:(NSString *)reuseIdentifier {
    self = [super initWithStyle:style reuseIdentifier:reuseIdentifier];
    if (self) {
        self.selectionStyle = UITableViewCellSelectionStyleNone;
        self.backgroundColor = [UIColor clearColor];
        [self setupUI];
    }
    return self;
}

- (void)prepareForReuse {
    [super prepareForReuse];
    self.messageLabel.text = @"";
    self.bubbleView.layer.mask = nil;
}


#pragma mark - setup UI

- (void)setupUI {
    [self addAllSubviews];
    [self addAllConstraints];
}

- (void)addAllSubviews {
    [self.contentView addSubview:self.avatarImageView];
    [self.contentView addSubview:self.bubbleView];
    [self.bubbleView addSubview:self.messageLabel];
}

- (void)addAllConstraints {
    [_avatarImageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.contentView).offset(ZOOM(16));
        make.top.equalTo(self.contentView).offset(ZOOM(8));
        make.width.height.mas_equalTo(ZOOM(32));
    }];

    [_bubbleView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.contentView).offset(ZOOM(8));
        make.left.equalTo(self.avatarImageView.mas_right).offset(ZOOM(8));
        make.right.lessThanOrEqualTo(self.contentView).offset(ZOOM(-16));
        make.bottom.equalTo(self.contentView).offset(ZOOM(-8));
        make.width.lessThanOrEqualTo(self.contentView.mas_width).multipliedBy(0.72);
    }];

    [_messageLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.bubbleView).offset(ZOOM(10));
        make.left.equalTo(self.bubbleView).offset(ZOOM(12));
        make.right.equalTo(self.bubbleView).offset(ZOOM(-12));
        make.bottom.equalTo(self.bubbleView).offset(ZOOM(-10));
    }];
}


#pragma mark - events

- (void)configureWithText:(NSString *)text isSender:(BOOL)isSender avatarImage:(UIImage * _Nullable)avatarImage {
    self.messageLabel.text = text ?: @"";
    self.isSenderFlag = isSender;
    self.avatarImageView.image = avatarImage;
    self.avatarImageView.hidden = isSender;

    // 重做约束以更新左右气泡位置
    [self.bubbleView mas_remakeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.contentView).offset(ZOOM(8));
        make.bottom.equalTo(self.contentView).offset(ZOOM(-8));
        make.width.lessThanOrEqualTo(self.contentView.mas_width).multipliedBy(0.72);
        if (isSender) {
            make.right.equalTo(self.contentView).offset(ZOOM(-16));
        } else {
            make.left.equalTo(self.avatarImageView.mas_right).offset(ZOOM(8));
        }
    }];

    if (isSender) {
        self.bubbleView.backgroundColor = RGBA(54, 179, 86, 1);
        self.messageLabel.textColor = [UIColor whiteColor];
    } else {
        self.bubbleView.backgroundColor = RGBA(245, 245, 245, 1);
        self.messageLabel.textColor = RGB(93, 93, 93);
    }

    // 交由布局阶段统一刷新蒙版，避免 bounds 未更新导致的错误
    [self setNeedsLayout];
}

- (void)setBubbleCornersForSender:(BOOL)isSender {
    CGFloat cornerRadius = ZOOM(12);
    CGRect bounds = self.bubbleView.bounds;

    if (CGRectIsEmpty(bounds)) {
        return;
    }

    UIBezierPath *path;

    if (isSender) {
        path = [UIBezierPath bezierPathWithRoundedRect:bounds
                                     byRoundingCorners:UIRectCornerTopLeft | UIRectCornerBottomLeft | UIRectCornerBottomRight
                                           cornerRadii:CGSizeMake(cornerRadius, cornerRadius)];
    } else {
        path = [UIBezierPath bezierPathWithRoundedRect:bounds
                                     byRoundingCorners:UIRectCornerTopRight | UIRectCornerBottomLeft | UIRectCornerBottomRight
                                           cornerRadii:CGSizeMake(cornerRadius, cornerRadius)];
    }

    CAShapeLayer *maskLayer = [CAShapeLayer layer];
    maskLayer.path = path.CGPath;
    self.bubbleView.layer.mask = maskLayer;
    [self.bubbleView layoutIfNeeded];
}

- (void)layoutSubviews {
    [super layoutSubviews];
    [self setBubbleCornersForSender:self.isSenderFlag];
}


#pragma mark - lazy load

- (UIView *)bubbleView {
    if (!_bubbleView) {
        _bubbleView = [[UIView alloc] init];
        _bubbleView.layer.masksToBounds = YES;
    }
    return _bubbleView;
}

- (UILabel *)messageLabel {
    if (!_messageLabel) {
        _messageLabel = [[UILabel alloc] init];
        _messageLabel.numberOfLines = 0;
        _messageLabel.font = [UIFont systemFontOfSize:ZOOM(16)];
        _messageLabel.lineBreakMode = NSLineBreakByWordWrapping;
    }
    return _messageLabel;
}


@end

- (UIImageView *)avatarImageView {
    if (!_avatarImageView) {
        _avatarImageView = [[UIImageView alloc] init];
        _avatarImageView.contentMode = UIViewContentModeScaleAspectFill;
        _avatarImageView.layer.cornerRadius = ZOOM(8);
        _avatarImageView.clipsToBounds = YES;
    }
    return _avatarImageView;
}

