- (void)speakMessageText:(NSString *)text {
    if (text.length == 0) return;
    if (self.speechSynthesizer.isSpeaking) {
        [self.speechSynthesizer stopSpeakingAtBoundary:AVSpeechBoundaryImmediate];
    }
    AVAudioSession *session = [AVAudioSession sharedInstance];
    NSError *sessionError = nil;
    [session setCategory:AVAudioSessionCategoryPlayback withOptions:AVAudioSessionCategoryOptionDuckOthers error:&sessionError];
    [session setActive:YES error:&sessionError];
    NSString *lang = [self isChineseText:text] ? @"zh-CN" : @"en-US";
    NSArray<NSString *> *chunks = [self chunkTextForUtterances:text];
    CGFloat baseRate = AVSpeechUtteranceDefaultSpeechRate;
    CGFloat rate = (text.length > 200) ? MAX(0.4, baseRate - 0.05) : baseRate;
    for (NSString *chunk in chunks) {
        AVSpeechUtterance *utt = [AVSpeechUtterance speechUtteranceWithString:chunk];
        utt.voice = [AVSpeechSynthesisVoice voiceWithLanguage:lang];
        utt.rate = rate;
        utt.pitchMultiplier = 1.0;
        utt.volume = 1.0;
        utt.postUtteranceDelay = 0.05;
        [self.speechSynthesizer speakUtterance:utt];
    }
}

- (void)enqueueSpeakText:(NSString *)text language:(NSString *)lang {
    if (text.length == 0) return;
    AVAudioSession *session = [AVAudioSession sharedInstance];
    NSError *sessionError = nil;
    [session setCategory:AVAudioSessionCategoryPlayback withOptions:AVAudioSessionCategoryOptionDuckOthers error:&sessionError];
    [session setActive:YES error:&sessionError];
    NSArray<NSString *> *chunks = [self chunkTextForUtterances:text];
    CGFloat baseRate = AVSpeechUtteranceDefaultSpeechRate;
    CGFloat rate = (text.length > 200) ? MAX(0.4, baseRate - 0.05) : baseRate;
    for (NSString *chunk in chunks) {
        AVSpeechUtterance *utt = [AVSpeechUtterance speechUtteranceWithString:chunk];
        utt.voice = [AVSpeechSynthesisVoice voiceWithLanguage:lang];
        utt.rate = rate;
        utt.pitchMultiplier = 1.0;
        utt.volume = 1.0;
        utt.postUtteranceDelay = 0.05;
//        [self.speechSynthesizer speakUtterance:utt];
    }
}

- (void)enqueueClosedSentencesForLatestAI {
    if (!self.voiceEnabled || self.messages.count == 0) return;
    AIChatListMessageModel *lastMessage = [self.messages lastObject];
    NSString *text = lastMessage.text ?: @"";
    if (text.length <= self.lastSpokenIndex) return;
    NSUInteger base = (NSUInteger)self.lastSpokenIndex;
    NSString *segment = [text substringFromIndex:base];
    NSArray<NSValue *> *ranges = [self closedSentenceRangesInSegment:segment baseOffset:base];
    if (ranges.count > 0) {
        for (NSValue *v in ranges) {
            NSRange r = [v rangeValue];
            if (r.location + r.length <= text.length && r.location >= self.lastSpokenIndex) {
                NSString *sentence = [text substringWithRange:r];
                NSString *lang = [self isChineseText:sentence] ? @"zh-CN" : @"en-US";
                [self enqueueSpeakText:sentence language:lang];
                self.lastSpokenIndex = (NSInteger)NSMaxRange(r);
            }
        }
    }
}

- (NSArray<NSValue *> *)closedSentenceRangesInSegment:(NSString *)segment baseOffset:(NSUInteger)base {
    NSMutableArray<NSValue *> *arr = [NSMutableArray array];
    if (segment.length == 0) return arr;
    NSCharacterSet *endSet = [NSCharacterSet characterSetWithCharactersInString:@"。！？!?\n\r."]; // 终止标点
    NSUInteger start = 0;
    for (NSUInteger i = 0; i < segment.length; i++) {
        unichar c = [segment characterAtIndex:i];
        if ([endSet characterIsMember:c]) {
            NSRange r = NSMakeRange(base + start, i - start + 1);
            [arr addObject:[NSValue valueWithRange:r]];
            start = i + 1;
        }
    }
    return arr;
}

- (NSArray<NSString *> *)chunkTextForUtterances:(NSString *)text {
    if (text.length <= 180) {
        return @[text];
    }
    NSMutableArray<NSString *> *chunks = [NSMutableArray array];
    NSArray<NSString *> *paragraphs = [text componentsSeparatedByCharactersInSet:[NSCharacterSet newlineCharacterSet]];
    NSCharacterSet *endPunct;
    if ([self isChineseText:text]) {
        endPunct = [NSCharacterSet characterSetWithCharactersInString:@"。！？!?；;：:" ];
    } else {
        endPunct = [NSCharacterSet characterSetWithCharactersInString:@".?!;:" ];
    }
    for (NSString *para in paragraphs) {
        NSString *p = [para stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
        if (p.length == 0) continue;
        if (p.length <= 220) {
            [chunks addObject:p];
            continue;
        }
        NSUInteger start = 0;
        while (start < p.length) {
            NSUInteger len = MIN(180, p.length - start);
            NSRange range = NSMakeRange(start, len);
            NSString *sub = [p substringWithRange:range];
            NSInteger cutIndex = -1;
            for (NSInteger i = sub.length - 1; i >= 0; i--) {
                unichar c = [sub characterAtIndex:i];
                if ([endPunct characterIsMember:c] || [[NSCharacterSet whitespaceCharacterSet] characterIsMember:c]) {
                    cutIndex = i;
                    break;
                }
            }
        if (cutIndex < 0) cutIndex = sub.length - 1;
        NSString *piece = [sub substringToIndex:cutIndex + 1];
        [chunks addObject:[piece stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]]];
        start += cutIndex + 1;
        }
    }
    return chunks.count ? chunks : @[text];
}

