- (NSInteger)tableView:(UITableView *)tableView numberOfRowsInSection:(NSInteger)section {
    return self.messages.count;
}

- (UITableViewCell *)tableView:(UITableView *)tableView cellForRowAtIndexPath:(NSIndexPath *)indexPath {
    AIChatListMessageCell *cell = [tableView dequeueReusableCellWithIdentifier:@"AIChatListMessageCell" forIndexPath:indexPath];
    AIChatListMessageModel *item = self.messages[indexPath.row];
    NSString *text = item.text ?: @"";
    BOOL isSender = (item.type == AIChatListMessageTypeSent);
    [cell configureWithText:text isSender:isSender avatarImage:isSender ? nil : [self conversationAvatarImage]];
    return cell;
}

- (CGFloat)tableView:(UITableView *)tableView heightForRowAtIndexPath:(NSIndexPath *)indexPath {
    AIChatListMessageModel *item = self.messages[indexPath.row];
    NSString *text = item.text ?: @"";
    if (text.length == 0) {
        return ZOOM(8 + 8 + 10 + 10) + ZOOM(18);
    }
    CGFloat contentWidth = CGRectGetWidth(tableView.bounds);
    CGFloat maxBubbleWidth = contentWidth * 0.72f;
    CGFloat labelHorizontalPadding = ZOOM(12) + ZOOM(12);
    CGFloat labelVerticalPadding = ZOOM(10) + ZOOM(10);
    CGFloat cellVerticalMargins = ZOOM(8) + ZOOM(8);
    CGFloat labelWidth = MAX(0.0, maxBubbleWidth - labelHorizontalPadding);
    CGRect bounding = [text boundingRectWithSize:CGSizeMake(labelWidth, CGFLOAT_MAX)
                                         options:(NSStringDrawingUsesLineFragmentOrigin | NSStringDrawingUsesFontLeading)
                                      attributes:@{ NSFontAttributeName: [UIFont systemFontOfSize:ZOOM(16)] }
                                         context:nil];
    CGFloat labelHeight = ceil(bounding.size.height);
    CGFloat cellHeight = labelHeight + labelVerticalPadding + cellVerticalMargins;
    CGFloat minHeight = ZOOM(44);
    return MAX(cellHeight, minHeight);
}

- (void)scrollToBottom {
    if (self.messages.count == 0) return;
    NSInteger lastRow = self.messages.count - 1;
    NSInteger numberOfRows = [self.tableView numberOfRowsInSection:0];
    if (lastRow >= 0 && lastRow < numberOfRows) {
        NSIndexPath *last = [NSIndexPath indexPathForRow:lastRow inSection:0];
        [self.tableView scrollToRowAtIndexPath:last atScrollPosition:UITableViewScrollPositionBottom animated:YES];
    } else {
        CGPoint bottomOffset = CGPointMake(0, self.tableView.contentSize.height - self.tableView.bounds.size.height + self.tableView.contentInset.bottom);
        [self.tableView setContentOffset:bottomOffset animated:YES];
    }
}

- (UIImage *)conversationAvatarImage {
    NSArray<AIChatListItemModel *> *list = [AIChatListStorage loadChatList];
    for (AIChatListItemModel *it in list) {
        if (![it.chatId isEqualToString:self.chatId]) {
            continue;
        }
        if (it.avatarPath.length > 0) {
            NSString *abs = [[AIChatListStorage documentsPath] stringByAppendingPathComponent:it.avatarPath];
            UIImage *img = [UIImage imageWithContentsOfFile:abs];
            if (img) {
                return img;
            }
        }
        if (it.icon.length > 0) {
            UIImage *img = [UIImage imageNamed:it.icon];
            if (img) {
                return img;
            }
        }
        break;
    }
    return [UIImage imageNamed:@"A_defaultAvatar"];
}


