@property (nonatomic, assign) BOOL isPlaying;

@end

static NSArray<NSDictionary *> *kPlayModes = nil;

@implementation SleepAidPlayView

+ (void)initialize {
    if (self == [SleepAidPlayView class]) {
        kPlayModes = @[
            @{@"title": @"Malam yang tenang", @"file": @"夜间昆虫-mp3.mp3", @"image": @"A_silent night"},
            @{@"title": @"Salju lebat", @"file": @"踩雪声.mp3", @"image": @"A_snow"},
            @{@"title": @"Gelombang pasang", @"file": @"海浪声.mp3", @"image": @"A_Grassland"}
        ];
    }
}

- (instancetype)init {
    self = [super init];
    if (self) {
        _currentModeIndex = 0;
        [self setUpUI];
        [self setUpEvents];
        [self refreshUI];
    }
    return self;
}

- (void)dealloc {
    if (self.timeObserver) {
        [self.player removeTimeObserver:self.timeObserver];
        self.timeObserver = nil;
    }
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

#pragma mark - Actions

- (void)togglePlayPause {
    if (self.isPlaying) {
        [self.player pause];
        self.isPlaying = NO;
        [self refreshUI];
        return;
    }

    if (!self.player) {
        [self preparePlayerForCurrentMode];
    }
    [self.player play];
    self.isPlaying = YES;
    [self refreshUI];
}

- (void)playNextMode {
    self.currentModeIndex = (self.currentModeIndex + 1) % kPlayModes.count;
    [self switchModeAndAutoplay];
}

- (void)playPreviousMode {
    self.currentModeIndex = (self.currentModeIndex - 1 + kPlayModes.count) % kPlayModes.count;
    [self switchModeAndAutoplay];
}

- (void)runLoopTheMovie:(NSNotification *)notification {
    [self.player seekToTime:kCMTimeZero];
    [self.player play];
    self.isPlaying = YES;
    [self refreshUI];
}

#pragma mark - UI

- (void)setUpUI {
    self.backgroundColor = BACKGROUND_COLOR;

    [self addSubview:self.modeview];
    [self addSubview:self.titleLabel];

    [self.modeview mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self).offset(ZOOMW(78));
        make.left.equalTo(self).offset(ZOOMW(16));
        make.right.equalTo(self).offset(-ZOOMW(16));
        make.height.mas_equalTo(ZOOMW(300));
    }];

    [self.titleLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.modeview.mas_bottom).offset(ZOOMW(28));
        make.centerX.equalTo(self);
    }];
}

- (void)setUpEvents {
    [self.modeview.playPauseButton addTarget:self action:@selector(togglePlayPause) forControlEvents:UIControlEventTouchUpInside];
    [self.modeview.previousButton addTarget:self action:@selector(playPreviousMode) forControlEvents:UIControlEventTouchUpInside];
    [self.modeview.nextButton addTarget:self action:@selector(playNextMode) forControlEvents:UIControlEventTouchUpInside];
}

- (void)refreshUI {
    NSDictionary *mode = kPlayModes[self.currentModeIndex];
    self.titleLabel.text = mode[@"title"];
    [self.modeview updateWithImageName:mode[@"image"]
                            statusText:(self.isPlaying ? @"Bermain" : @"Berhenti sebentar")
                             isPlaying:self.isPlaying];
}

#pragma mark - Player

- (void)switchModeAndAutoplay {
    [self.player pause];
    [self preparePlayerForCurrentMode];
    [self.player play];
    self.isPlaying = YES;
    [self refreshUI];
}

- (void)preparePlayerForCurrentMode {
    if (self.timeObserver && self.player) {
        [self.player removeTimeObserver:self.timeObserver];
        self.timeObserver = nil;
    }

    NSDictionary *mode = kPlayModes[self.currentModeIndex];
    NSURL *url = [[NSBundle mainBundle] URLForResource:mode[@"file"] withExtension:nil];
    if (!url) {
        self.player = nil;
        self.isPlaying = NO;
        [self refreshUI];
        return;
    }

    self.player = [AVPlayer playerWithPlayerItem:[AVPlayerItem playerItemWithURL:url]];
    [self addPlayerObserver];

    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        AVAudioSession *audioSession = [AVAudioSession sharedInstance];
        [audioSession setCategory:AVAudioSessionCategoryPlayback withOptions:AVAudioSessionCategoryOptionMixWithOthers error:nil];
        [audioSession setActive:YES error:nil];
    });

    [[NSNotificationCenter defaultCenter] removeObserver:self name:AVPlayerItemDidPlayToEndTimeNotification object:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(runLoopTheMovie:) name:AVPlayerItemDidPlayToEndTimeNotification object:self.player.currentItem];
}

- (void)addPlayerObserver {
    __weak typeof(self) weakSelf = self;
    self.timeObserver = [self.player addPeriodicTimeObserverForInterval:CMTimeMake(1, 5) queue:dispatch_get_main_queue() usingBlock:^(CMTime time) {
        __strong typeof(weakSelf) self = weakSelf;
        if (!self) return;
        BOOL playing = self.player.rate != 0 && self.player.error == nil;
        if (self.isPlaying != playing) {
            self.isPlaying = playing;
            [self refreshUI];
        }
    }];
}

#pragma mark - Lazy

- (SleepAidModeView *)modeview {
    if (_modeview == nil) {
        _modeview = [[SleepAidModeView alloc] init];
    }
    return _modeview;
}

- (UILabel *)titleLabel {
    if (_titleLabel == nil) {
        _titleLabel = [[UILabel alloc] init];
        _titleLabel.font = [UIFont boldSystemFontOfSize:ZOOMW(18)];
        _titleLabel.textColor = RGB(79, 79, 79);
        _titleLabel.textAlignment = NSTextAlignmentCenter;
    }
    return _titleLabel;
}

@end

