@implementation SleepAidModeView

- (instancetype)init {
    self = [super init];
    if (self) {
        [self setUpUI];
    }
    return self;
}

- (void)layoutSubviews {
    [super layoutSubviews];

    self.cardView.layer.cornerRadius = ZOOMW(36);
    self.cardView.layer.masksToBounds = YES;
}

- (void)setUpUI {
    self.backgroundColor = [UIColor clearColor];

    [self addSubview:self.cardView];
    [self.cardView addSubview:self.backgroundImageView];
    [self.cardView addSubview:self.statusLabel];
    [self.cardView addSubview:self.previousButton];
    [self.cardView addSubview:self.playPauseButton];
    [self.cardView addSubview:self.nextButton];

    [self.cardView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(self);
    }];

    [self.backgroundImageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.edges.equalTo(self.cardView);
    }];

    [self.statusLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerX.equalTo(self.cardView);
        make.centerY.equalTo(self.cardView).offset(ZOOMW(24));
    }];

    [self.playPauseButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerX.equalTo(self.cardView);
        make.bottom.equalTo(self.cardView).offset(-ZOOMW(46));
        make.width.height.mas_equalTo(ZOOMW(52));
    }];

    [self.previousButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(self.playPauseButton);
        make.centerX.equalTo(self.cardView).offset(-ZOOMW(72));
        make.width.height.mas_equalTo(ZOOMW(28));
    }];

    [self.nextButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerY.equalTo(self.playPauseButton);
        make.centerX.equalTo(self.cardView).offset(ZOOMW(72));
        make.width.height.mas_equalTo(ZOOMW(28));
    }];
}

- (void)updateWithImageName:(NSString *)imageName statusText:(NSString *)statusText isPlaying:(BOOL)isPlaying {
    UIImage *image = [UIImage imageNamed:imageName];
    self.backgroundImageView.image = image;
    self.statusLabel.text = statusText;

    NSString *symbolName = isPlaying ? @"pause.fill" : @"play.fill";
    UIImage *centerImage = nil;
    UIImage *sideImage = nil;
    if (@available(iOS 13.0, *)) {
        UIImageSymbolConfiguration *centerConfig = [UIImageSymbolConfiguration configurationWithPointSize:ZOOMW(26) weight:UIImageSymbolWeightBold];
        centerImage = [[UIImage systemImageNamed:symbolName withConfiguration:centerConfig] imageWithTintColor:UIColor.whiteColor renderingMode:UIImageRenderingModeAlwaysOriginal];
        UIImageSymbolConfiguration *sideConfig = [UIImageSymbolConfiguration configurationWithPointSize:ZOOMW(18) weight:UIImageSymbolWeightBold];
        sideImage = [[UIImage systemImageNamed:@"forward.fill" withConfiguration:sideConfig] imageWithTintColor:UIColor.whiteColor renderingMode:UIImageRenderingModeAlwaysOriginal];
    } else {
        centerImage = [UIImage imageNamed:isPlaying ? @"A_Selectedplay" : @"A_Selectedpause"];
        sideImage = [UIImage imageNamed:@"A_Selectedpause"];
    }

    [self.playPauseButton setImage:centerImage forState:UIControlStateNormal];
    [self.previousButton setImage:sideImage forState:UIControlStateNormal];
    [self.nextButton setImage:sideImage forState:UIControlStateNormal];
    self.previousButton.transform = CGAffineTransformMakeRotation(M_PI);
    self.nextButton.transform = CGAffineTransformIdentity;
}

- (UIView *)cardView {
    if (!_cardView) {
        _cardView = [[UIView alloc] init];
        _cardView.backgroundColor = [UIColor clearColor];
    }
    return _cardView;
}

- (UIImageView *)backgroundImageView {
    if (!_backgroundImageView) {
        _backgroundImageView = [[UIImageView alloc] init];
        _backgroundImageView.contentMode = UIViewContentModeScaleAspectFill;
        _backgroundImageView.clipsToBounds = YES;
    }
    return _backgroundImageView;
}

- (UILabel *)statusLabel {
    if (!_statusLabel) {
        _statusLabel = [[UILabel alloc] init];
        _statusLabel.font = [UIFont boldSystemFontOfSize:ZOOMW(18)];
        _statusLabel.textColor = UIColor.whiteColor;
        _statusLabel.layer.shadowColor = RGBA(0, 0, 0, 0.16).CGColor;
        _statusLabel.layer.shadowOffset = CGSizeMake(0, ZOOMW(2));
        _statusLabel.layer.shadowOpacity = 1;
        _statusLabel.layer.shadowRadius = ZOOMW(8);
    }
    return _statusLabel;
}

- (UIButton *)playPauseButton {
    if (!_playPauseButton) {
        _playPauseButton = [UIButton buttonWithType:UIButtonTypeCustom];
        _playPauseButton.backgroundColor = RGBA(70, 225, 151, 1);
        _playPauseButton.layer.cornerRadius = ZOOMW(26);
