        _playPauseButton.layer.shadowColor = RGBA(0, 0, 0, 0.18).CGColor;
        _playPauseButton.layer.shadowOffset = CGSizeMake(0, ZOOMW(8));
        _playPauseButton.layer.shadowOpacity = 1;
        _playPauseButton.layer.shadowRadius = ZOOMW(16);
    }
    return _playPauseButton;
}

- (UIButton *)previousButton {
    if (!_previousButton) {
        _previousButton = [UIButton buttonWithType:UIButtonTypeCustom];
    }
    return _previousButton;
}

- (UIButton *)nextButton {
    if (!_nextButton) {
        _nextButton = [UIButton buttonWithType:UIButtonTypeCustom];
    }
    return _nextButton;
}

@end

