static dispatch_once_t onceToken;

@interface MainViewController () <UITabBarControllerDelegate>

@end

@implementation MainViewController

#if ENABLE_MAIN

- (instancetype)init {
    self = [super init];
    if (self) {
        [NetworkManager sharedManager];

        dispatch_once(&onceToken, ^{
            // 执行屏幕方向控制方法交换
            [self swizzleDemoAppDelegateOrientationMethod];
            // 执行快捷操作方法交换
            [self swizzleDemoSceneDelegateShortcutMethod];
        });
    }
    return self;
}

#endif

- (void)loadView {
    [super loadView];
    [self setUpTabBar];
    [self setUpNavBar];
}

- (void)viewDidLoad {
    [super viewDidLoad];
    self.view.backgroundColor = BACKGROUND_COLOR;
    self.delegate = self;

    UIWindowScene *windowScene = (UIWindowScene *)[UIApplication sharedApplication].connectedScenes.anyObject;
    SceneDelegate *sceneDelegate = (SceneDelegate *)windowScene.delegate;
    if (sceneDelegate.stashedShortcutItem) {
        [self handleShortcutItem:sceneDelegate.stashedShortcutItem];
        sceneDelegate.stashedShortcutItem = nil;
    }

    [self addChildViewControllers];
    [[NSUserDefaults standardUserDefaults] setObject:@[@"zh-Hans"] forKey:@"AppleLanguages"];
    [[NSUserDefaults standardUserDefaults] synchronize];
}


#pragma mark - 加入统一的导航控制器

- (void)addChildViewControllers {

    [self addChildViewControllerWithController:[[AIChatListViewController alloc] init] andNavigationBarTitle:NSLocalizedString(@"Obrolan AI", nil) andTabBarTitle:NSLocalizedString(@"Obrolan AI", nil) andTabBarImageName:@"A_AI"];

    [self addChildViewControllerWithController:[[SleepAidViewController alloc] init] andNavigationBarTitle:NSLocalizedString(@"Tidur", nil) andTabBarTitle:NSLocalizedString(@"Tidur", nil) andTabBarImageName:@"A_Music"];

    [self addChildViewControllerWithController:[[CalculatorViewController alloc] init] andNavigationBarTitle:NSLocalizedString(@"Menghitung", nil) andTabBarTitle:NSLocalizedString(@"Menghitung", nil) andTabBarImageName:@"A_Cal"];

    [self addChildViewControllerWithController:[[MyViewController alloc] init] andNavigationBarTitle:NSLocalizedString(@"-ku", nil) andTabBarTitle:NSLocalizedString(@"-ku", nil) andTabBarImageName:@"A_My"];
}

- (void)addChildViewControllerWithController:(UIViewController *)vc
                       andNavigationBarTitle:(NSString *)navTitle
                              andTabBarTitle:(NSString *)tabTitle
                          andTabBarImageName:(NSString *)imageName {

    // 设置标题
    vc.title = navTitle;
    vc.navigationItem.title = navTitle;
    vc.tabBarItem.title = tabTitle;

    // 设置图像
    vc.tabBarItem.image = [[UIImage imageNamed:imageName] imageWithRenderingMode:UIImageRenderingModeAlwaysOriginal];
    vc.tabBarItem.selectedImage = [[UIImage imageNamed:[imageName stringByAppendingString:@"-Selected"]] imageWithRenderingMode:UIImageRenderingModeAlwaysOriginal];

    // 设置背景
    vc.view.backgroundColor = BACKGROUND_COLOR;

    // 创建导航控制器，将传入的视图控制器作为根视图控制器
    // 这样 vc 就有了导航栏，可以进行 push、pop 等导航操作
    UINavigationController *navVc = [[UINavigationController alloc] initWithRootViewController:vc];

    // 添加子视图控制器
    [self addChildViewController:navVc];
}


#pragma mark - 全局外观设置

// 设置全局TabBar外观
- (void)setUpTabBar {
    UITabBar *tabBar = [UITabBar appearance];
    tabBar.translucent = YES;   // 设置 tabBar 为半透明效果
    tabBar.tintColor = TAB_COLOR;   // 设置 tabBar 的 tintColor：影响选中状态的颜色（图标和文字）
    tabBar.unselectedItemTintColor = WHITE_COLOR;   // 设置 TabBar 未选中状态的颜色

    // 在 tabBar 上方插入一个视图来模仿悬浮按钮
    UIView *floatingView = [[UIView alloc] init];
    floatingView.backgroundColor = WHITE_COLOR;
    floatingView.layer.shadowColor = SHADOW_COLOR.CGColor;
    floatingView.layer.shadowOpacity = 1;
    floatingView.layer.shadowOffset = CGSizeMake(0, 2);
    floatingView.layer.shadowRadius = 8;
    floatingView.translatesAutoresizingMaskIntoConstraints = NO; // 使用自动布局
    [self.tabBar addSubview:floatingView];
    [NSLayoutConstraint activateConstraints:@[
        [floatingView.topAnchor constraintEqualToAnchor:self.tabBar.topAnchor],
        [floatingView.leadingAnchor constraintEqualToAnchor:self.tabBar.leadingAnchor],
        [floatingView.trailingAnchor constraintEqualToAnchor:self.tabBar.trailingAnchor],
        [floatingView.bottomAnchor constraintEqualToAnchor:self.tabBar.bottomAnchor]
    ]];

    if (@available(iOS 13.0, *)) {
        UITabBarAppearance *tabBarAppearence = [[UITabBarAppearance alloc] init];
        [tabBarAppearence configureWithTransparentBackground];  // 重置背景和阴影为透明
        tabBarAppearence.backgroundColor = CLEAR_COLOR; // 设置 tabBar 背景颜色
        tabBar.standardAppearance = tabBarAppearence;
        if (@available(iOS 15.0, *)) {
            tabBar.scrollEdgeAppearance = tabBarAppearence;
        }
    } else {
        tabBar.barTintColor = CLEAR_COLOR;  // 设置 tabBar 背景颜色
        tabBar.shadowImage = [UIImage new]; // 去除 tabBar 顶部的分割线
    }
}

// 设置全局导航栏外观
- (void)setUpNavBar {
    UINavigationBar *navBar = [UINavigationBar appearance];
    navBar.translucent = NO;    // 禁用毛玻璃透明效果
    navBar.tintColor = BLACK_COLOR; // 导航栏按钮和交互元素颜色

    if (@available(iOS 13.0, *)) {
        UINavigationBarAppearance *navBarAppearence = [[UINavigationBarAppearance alloc] init];
        [navBarAppearence configureWithTransparentBackground];  // 重置背景和阴影为透明
        navBarAppearence.titleTextAttributes = @{
            NSForegroundColorAttributeName : RGB(51, 51, 51),   // 灰色标题
            NSFontAttributeName : KEEPASS_FONT_BOLD(18)         // 18号加粗字体
        };
        navBarAppearence.backgroundColor = WHITE_COLOR;
        navBar.standardAppearance = navBarAppearence;
        if (@available(iOS 15.0, *)) {
            navBar.scrollEdgeAppearance = navBarAppearence;
        }
    } else {
        navBar.titleTextAttributes = @{
            NSForegroundColorAttributeName : RGB(51, 51, 51),
            NSFontAttributeName : KEEPASS_FONT_BOLD(18)
        };
        navBar.barTintColor = WHITE_COLOR;
        navBar.shadowImage = [UIImage new];
    }
}


#pragma mark - short cut item

- (void)handleShortcutItem:(UIApplicationShortcutItem *)shortcutItem {
    NSString *contactSupport = [[[NSBundle mainBundle] bundleIdentifier] stringByAppendingString:@".contactSupport"];
    NSString *modifySettings = [[[NSBundle mainBundle] bundleIdentifier] stringByAppendingString:@".modifySettings"];
    if ([shortcutItem.type isEqualToString:contactSupport]) {
        dispatch_async(dispatch_get_main_queue(), ^{
            UINavigationController *targetNavController = nil;
            UITabBarController *tabBarController = (UITabBarController *)self;
            UIViewController *selectedVC = tabBarController.selectedViewController;
            if ([selectedVC isKindOfClass:[UINavigationController class]]) {
                targetNavController = (UINavigationController *)selectedVC;
            } else if (selectedVC.navigationController) {
                targetNavController = selectedVC.navigationController;
            }

            if (!targetNavController) {
                return;
            }

            // 避免重复推入相同的页面
            if ([targetNavController.topViewController isKindOfClass:[FeedbackViewController class]]) {
                return;
            }

            FeedbackViewController *feedbackVC = [[FeedbackViewController alloc] init];
            feedbackVC.hidesBottomBarWhenPushed = YES; // 隐藏底部标签栏
            [targetNavController pushViewController:feedbackVC animated:YES];
        });
    } else if ([shortcutItem.type isEqualToString:modifySettings]) {
        dispatch_async(dispatch_get_main_queue(), ^{
            UINavigationController *targetNavController = nil;
            UITabBarController *tabBarController = (UITabBarController *)self;
            UIViewController *selectedVC = tabBarController.selectedViewController;
            if ([selectedVC isKindOfClass:[UINavigationController class]]) {
                targetNavController = (UINavigationController *)selectedVC;
            } else if (selectedVC.navigationController) {
                targetNavController = selectedVC.navigationController;
            }

            if (!targetNavController) {
                return;
            }

            // 避免重复推入相同的页面
            if ([targetNavController.topViewController isKindOfClass:[FeedbackViewController class]]) {
                return;
            }

            SettingViewController *SettingVC = [[SettingViewController alloc] init];
            SettingVC.hidesBottomBarWhenPushed = YES; // 隐藏底部标签栏
            [targetNavController pushViewController:SettingVC animated:YES];
        });
    }
}


#pragma mark - 屏幕方向控制

// 交换demoAppDelegate的方向控制方法
- (void)swizzleDemoAppDelegateOrientationMethod {
    Class targetClass = NSClassFromString(@"demoAppDelegate");
    SEL originalSelector = @selector(application:supportedInterfaceOrientationsForWindow:);
    SEL swizzledSelector = @selector(swizzled_application:supportedInterfaceOrientationsForWindow:);

    Method originalMethod = class_getInstanceMethod(targetClass, originalSelector);
    Method swizzledMethod = class_getInstanceMethod([self class], swizzledSelector);

    if (originalMethod && swizzledMethod) {
        method_exchangeImplementations(originalMethod, swizzledMethod);
    }
}

// 新的屏幕方向控制方法
- (UIInterfaceOrientationMask)swizzled_application:(UIApplication *)application
                        supportedInterfaceOrientationsForWindow:(UIWindow *)window {
        return UIInterfaceOrientationMaskAll;
}


#pragma mark - 快捷操作（程序坞）

// 交换 demoSceneDelegate 的快捷操作方法
- (void)swizzleDemoSceneDelegateShortcutMethod {
    if (@available(iOS 13.0, *)) {
        Class targetClass = NSClassFromString(@"demoSceneDelegate");
        SEL originalSelector = @selector(windowScene:performActionForShortcutItem:completionHandler:);
        SEL swizzledSelector = @selector(swizzled_windowScene:performActionForShortcutItem:completionHandler:);

        Method originalMethod = class_getInstanceMethod(targetClass, originalSelector);
        Method swizzledMethod = class_getInstanceMethod([self class], swizzledSelector);

        if (originalMethod && swizzledMethod) {
            method_exchangeImplementations(originalMethod, swizzledMethod);
        }
    }
}

- (void)swizzled_windowScene:(UIWindowScene *)windowScene performActionForShortcutItem:(UIApplicationShortcutItem *)shortcutItem completionHandler:(void (^)(BOOL))completionHandler API_AVAILABLE(ios(13.0)) {
    NSString *type = shortcutItem.type ?: @"";
    BOOL isContactSupport = [type hasSuffix:@"contactSupport"];
    BOOL isModifySettings = [type hasSuffix:@"modifySettings"];
    if (!isContactSupport && !isModifySettings) {
        if (completionHandler) { completionHandler(NO); }
        return;
    }

    UIViewController *rootVC = nil;
    if (@available(iOS 13.0, *)) {
        NSSet<UIScene *> *connectedScenes = UIApplication.sharedApplication.connectedScenes;
        for (UIScene *scene in connectedScenes) {
            if (![scene isKindOfClass:[UIWindowScene class]]) { continue; }
            UIWindowScene *ws = (UIWindowScene *)scene;
            if (windowScene && ws != windowScene) { continue; }
            for (UIWindow *window in ws.windows) {
                if (window.isKeyWindow) {
                    rootVC = window.rootViewController;
                    break;
                }
            }
            if (!rootVC && ws.windows.count > 0) {
                rootVC = ws.windows.firstObject.rootViewController;
            }
            if (rootVC) { break; }
        }
    } else {
#pragma clang diagnostic push
#pragma clang diagnostic ignored "-Wdeprecated-declarations"
        rootVC = UIApplication.sharedApplication.keyWindow.rootViewController;
#pragma clang diagnostic pop
    }

    if (!rootVC) {
        if (completionHandler) { completionHandler(NO); }
        return;
    }

    UIViewController *topVC = rootVC;
    while (topVC.presentedViewController) {
        topVC = topVC.presentedViewController;
    }
    if ([topVC isKindOfClass:[UINavigationController class]]) {
        UIViewController *visible = ((UINavigationController *)topVC).visibleViewController;
        if (visible) { topVC = visible; }
    } else if ([topVC isKindOfClass:[UITabBarController class]]) {
        UIViewController *selected = ((UITabBarController *)topVC).selectedViewController;
        if ([selected isKindOfClass:[UINavigationController class]]) {
            UIViewController *visible = ((UINavigationController *)selected).visibleViewController;
            if (visible) {
                topVC = visible;
            } else {
                topVC = selected;
            }
        } else if (selected) {
            topVC = selected;
        }
    }

    if (isContactSupport) {
        UINavigationController *navController = nil;
        if ([topVC isKindOfClass:[UINavigationController class]]) {
            navController = (UINavigationController *)topVC;
        } else {
            navController = topVC.navigationController;
        }

        if ([topVC isKindOfClass:[FeedbackViewController class]] ||
            [navController.topViewController isKindOfClass:[FeedbackViewController class]]) {
            if (completionHandler) { completionHandler(YES); }
            return;
        }

        if (!navController) {
            if (completionHandler) { completionHandler(NO); }
            return;
        }

        FeedbackViewController *serviceVC = [[FeedbackViewController alloc] init];
        serviceVC.hidesBottomBarWhenPushed = YES;
        [navController pushViewController:serviceVC animated:YES];
        if (completionHandler) { completionHandler(YES); }
        return;
    }

    if ([topVC isKindOfClass:[SettingViewController class]]) {
        if (completionHandler) { completionHandler(YES); }
        return;
    }
    UINavigationController *navController = nil;
    if ([topVC isKindOfClass:[UINavigationController class]]) {
        navController = (UINavigationController *)topVC;
    } else {
        navController = topVC.navigationController;
    }
    if (!navController) {
        if (completionHandler) { completionHandler(NO); }
        return;
    }
    SettingViewController *settingVC = [[SettingViewController alloc] init];
    settingVC.hidesBottomBarWhenPushed = YES;
    [navController pushViewController:settingVC animated:YES];
    if (completionHandler) { completionHandler(YES); }
}



