                            statusText:(self.isPlaying ? @"Bermain" : @"Berhenti sebentar")
                             isPlaying:self.isPlaying];
}

#pragma mark - Player

- (void)switchModeAndAutoplay {
    [self.player pause];
    [self preparePlayerForCurrentMode];
    [self.player play];
    self.isPlaying = YES;
    [self refreshUI];
}

- (void)preparePlayerForCurrentMode {
    if (self.timeObserver && self.player) {
        [self.player removeTimeObserver:self.timeObserver];
        self.timeObserver = nil;
    }

    NSDictionary *mode = kPlayModes[self.currentModeIndex];
    NSURL *url = [[NSBundle mainBundle] URLForResource:mode[@"file"] withExtension:nil];
    if (!url) {
        self.player = nil;
        self.isPlaying = NO;
        [self refreshUI];
        return;
    }

    self.player = [AVPlayer playerWithPlayerItem:[AVPlayerItem playerItemWithURL:url]];
    [self addPlayerObserver];

    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        AVAudioSession *audioSession = [AVAudioSession sharedInstance];
        [audioSession setCategory:AVAudioSessionCategoryPlayback withOptions:AVAudioSessionCategoryOptionMixWithOthers error:nil];
        [audioSession setActive:YES error:nil];
    });

    [[NSNotificationCenter defaultCenter] removeObserver:self name:AVPlayerItemDidPlayToEndTimeNotification object:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(runLoopTheMovie:) name:AVPlayerItemDidPlayToEndTimeNotification object:self.player.currentItem];
}

- (void)addPlayerObserver {
    __weak typeof(self) weakSelf = self;
    self.timeObserver = [self.player addPeriodicTimeObserverForInterval:CMTimeMake(1, 5) queue:dispatch_get_main_queue() usingBlock:^(CMTime time) {
        __strong typeof(weakSelf) self = weakSelf;
        if (!self) return;
        BOOL playing = self.player.rate != 0 && self.player.error == nil;
        if (self.isPlaying != playing) {
            self.isPlaying = playing;
            [self refreshUI];
        }
    }];
}

