- (void)configureWithImageURL:(NSString *)imageURL imageSize:(CGSize)imageSize isSender:(BOOL)isSender {
    self.isSenderFlag = isSender;
    self.messageLabel.hidden = YES;
    self.messageImageView.hidden = NO;
    self.avatarImageView.image = [UIImage imageNamed:(isSender ? @"A_user" : @"A_service")];

    [self updateAvatarAndBubbleConstraintsForSender:isSender];

    if (isSender) {
        self.bubbleView.backgroundColor = USER_BUBBLEVIEW;
    } else {
        self.bubbleView.backgroundColor = SERVICE_BUBBLEVIEW;
    }

    CGFloat presetRatio = (imageSize.height > 0.0f) ? (imageSize.width / imageSize.height) : 0.0f;
    CGFloat presetFixedW = (presetRatio > 1.0f) ? ZOOM(220) : ZOOM(160);
    CGFloat presetMaxW = [UIScreen mainScreen].bounds.size.width * 0.7f;
    CGFloat presetW = (presetRatio > 0.0f) ? MIN(presetFixedW, presetMaxW) : ZOOM(160);
    CGFloat presetH = (presetRatio > 0.0f) ? (presetW / presetRatio) : ZOOM(180);

    [self.messageImageView mas_remakeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.bubbleView).offset(ZOOM(6));
        if (isSender) {
            make.right.equalTo(self.bubbleView).offset(ZOOM(-6));
        } else {
            make.left.equalTo(self.bubbleView).offset(ZOOM(6));
        }
        make.bottom.equalTo(self.bubbleView).offset(ZOOM(-6));
        make.width.mas_equalTo(presetW);
        make.height.mas_equalTo(presetH);
    }];

    [self.imageTask cancel];
    self.imageTask = nil;
    self.currentImageURL = imageURL;
    self.messageImageView.image = nil;

    if (![imageURL isKindOfClass:NSString.class] || imageURL.length == 0) {
        return;
    }
    if ([imageURL hasPrefix:@"data:image"]) {
        NSRange commaRange = [imageURL rangeOfString:@","];
        NSString *base64Part = (commaRange.location != NSNotFound && commaRange.location + 1 < imageURL.length) ? [imageURL substringFromIndex:commaRange.location + 1] : @"";
        NSData *rawData = [[NSData alloc] initWithBase64EncodedString:base64Part options:NSDataBase64DecodingIgnoreUnknownCharacters];
        UIImage *img = rawData ? [UIImage imageWithData:rawData] : nil;
        if (img) {
            self.messageImageView.image = img;
            CGFloat sw = [UIScreen mainScreen].bounds.size.width;
            CGFloat maxW = sw * 0.7f;
            CGFloat iw = img.size.width;
            CGFloat ih = img.size.height;
            CGFloat ratio = (ih > 0.0f) ? (iw / ih) : 1.0f;
            BOOL isLandscape = ratio > 1.0f;
            CGFloat fixedW = isLandscape ? ZOOM(220) : ZOOM(160);
            CGFloat W = MIN(fixedW, maxW);
            CGFloat H = (ratio > 0.0f) ? (W / ratio) : ZOOM(180);
            [self.messageImageView mas_remakeConstraints:^(MASConstraintMaker *make) {
                make.top.equalTo(self.bubbleView).offset(ZOOM(6));
                if (self.isSenderFlag) {
                    make.right.equalTo(self.bubbleView).offset(ZOOM(-6));
                } else {
                    make.left.equalTo(self.bubbleView).offset(ZOOM(6));
                }
                make.width.mas_equalTo(W);
                make.height.mas_equalTo(H);
                make.bottom.equalTo(self.bubbleView).offset(ZOOM(-6));
            }];
            if (self.onImageSizeUpdate &&
                (fabs(img.size.width - imageSize.width) > 0.5f || fabs(img.size.height - imageSize.height) > 0.5f)) {
                self.onImageSizeUpdate(img.size);
            }
            [self setNeedsLayout];
            return;
        }
    }
    NSURL *url = [NSURL URLWithString:imageURL];
    if (!url) {
        NSData *rawData = [[NSData alloc] initWithBase64EncodedString:imageURL options:NSDataBase64DecodingIgnoreUnknownCharacters];
        UIImage *img = rawData ? [UIImage imageWithData:rawData] : nil;
        if (!img) { return; }
        self.messageImageView.image = img;
        CGFloat sw = [UIScreen mainScreen].bounds.size.width;
        CGFloat maxW = sw * 0.7f;
        CGFloat iw = img.size.width;
        CGFloat ih = img.size.height;
        CGFloat ratio = (ih > 0.0f) ? (iw / ih) : 1.0f;
        BOOL isLandscape = ratio > 1.0f;
        CGFloat fixedW = isLandscape ? ZOOM(220) : ZOOM(160);
        CGFloat W = MIN(fixedW, maxW);
        CGFloat H = (ratio > 0.0f) ? (W / ratio) : ZOOM(180);
        [self.messageImageView mas_remakeConstraints:^(MASConstraintMaker *make) {
            make.top.equalTo(self.bubbleView).offset(ZOOM(6));
            if (self.isSenderFlag) {
                make.right.equalTo(self.bubbleView).offset(ZOOM(-6));
            } else {
                make.left.equalTo(self.bubbleView).offset(ZOOM(6));
            }
            make.width.mas_equalTo(W);
            make.height.mas_equalTo(H);
            make.bottom.equalTo(self.bubbleView).offset(ZOOM(-6));
        }];
        if (self.onImageSizeUpdate &&
            (fabs(img.size.width - imageSize.width) > 0.5f || fabs(img.size.height - imageSize.height) > 0.5f)) {
            self.onImageSizeUpdate(img.size);
        }
        [self setNeedsLayout];
        return;
    }
    __weak typeof(self) weakSelf = self;
    NSURLSessionDataTask *task = [[NSURLSession sharedSession] dataTaskWithURL:url completionHandler:^(NSData * _Nullable data, NSURLResponse * _Nullable response, NSError * _Nullable error) {
        if (error || !data) {
            return;
        }
        UIImage *img = [UIImage imageWithData:data];
        if (!img) { return; }
        dispatch_async(dispatch_get_main_queue(), ^{
            if (![weakSelf.currentImageURL isEqualToString:imageURL]) { return; }
            weakSelf.messageImageView.image = img;
            CGFloat sw = [UIScreen mainScreen].bounds.size.width;
            CGFloat maxW = sw * 0.7f;
            CGFloat iw = img.size.width;
            CGFloat ih = img.size.height;
            CGFloat ratio = (ih > 0.0f) ? (iw / ih) : 1.0f;
            BOOL isLandscape = ratio > 1.0f;
            CGFloat fixedW = isLandscape ? ZOOMW(220) : ZOOMW(160);
            CGFloat W = MIN(fixedW, maxW);
            CGFloat H = (ratio > 0.0f) ? (W / ratio) : ZOOM(180);

            [weakSelf.messageImageView mas_remakeConstraints:^(MASConstraintMaker *make) {
                make.top.equalTo(weakSelf.bubbleView).offset(ZOOM(6));
                if (weakSelf.isSenderFlag) {
                    make.right.equalTo(weakSelf.bubbleView).offset(ZOOM(-6));
                } else {
                    make.left.equalTo(weakSelf.bubbleView).offset(ZOOM(6));
                }
                make.width.mas_equalTo(W);
                make.height.mas_equalTo(H);
                make.bottom.equalTo(weakSelf.bubbleView).offset(ZOOM(-6));
            }];

            [weakSelf.bubbleView mas_remakeConstraints:^(MASConstraintMaker *make) {
                make.top.equalTo(weakSelf.contentView).offset(ZOOM(8));
                make.bottom.equalTo(weakSelf.contentView).offset(ZOOM(-8));
                make.width.lessThanOrEqualTo(weakSelf.contentView.mas_width).multipliedBy(0.72f);
                if (weakSelf.isSenderFlag) {
                    make.right.equalTo(weakSelf.avatarImageView.mas_left).offset(ZOOM(-10));
                    make.left.equalTo(weakSelf.messageImageView.mas_left).offset(ZOOM(-6));
                } else {
                    make.left.equalTo(weakSelf.avatarImageView.mas_right).offset(ZOOM(10));
                    make.right.equalTo(weakSelf.messageImageView.mas_right).offset(ZOOM(6));
                }
            }];

            if (weakSelf.onImageSizeUpdate &&
                (fabs(img.size.width - imageSize.width) > 0.5f || fabs(img.size.height - imageSize.height) > 0.5f)) {
                weakSelf.onImageSizeUpdate(img.size);
            }
            [weakSelf setNeedsLayout];
        });
    }];
    self.imageTask = task;
    [task resume];
    [self setNeedsLayout];
}

